INSERT INTO insights (empresa_id, indicador_key, periodo_ano, year, period_key, tipo, analisis_positivo, analisis_negativo, recomendacion, metodologia, generado_por, created_at)
VALUES 
(3099, 'cobertura_fijos_1Q', 2023, 2023, '1Q', 'success', 'En este primer trimestre del 2023, tu cobertura de activos fijos se mantiene sólida cerca del 1.0x. Es una señal clara de que estás iniciando el año con una estructura patrimonial que respalda perfectamente tus inversiones de largo plazo, garantizando que el negocio no tenga que depender de deudas externas para mantener su infraestructura.', 'El aspecto negativo es que no cuentas con un excedente de cobertura que te permita absorber renovaciones tecnológicas de emergencia. Estás operando en el punto de equilibrio exacto, lo que significa que cualquier daño mayor en equipos o necesidad de licencias nuevas te obligaría a sacrificar flujo de caja operativo de corto plazo.', 'Te recomiendo que empieces a provisionar un fondo para la reposición de activos fijos desde este mismo mes. Busca que tu cobertura patrimonial suba gradualmente para que al cierre del año tengas un respiro estratégico que te permita innovar sin presiones financieras.', 'Bloque C - Trimestral 1Q 2023', 'antigravity', NOW()),
(3099, 'cobertura_fijos_2Q', 2023, 2023, '2Q', 'success', 'Llegamos a la mitad del año con una cobertura que sigue demostrando tu disciplina financiera. Has logrado que tus activos fijos sigan 100% respaldados por tu capital social, lo que blinda a la consultora contra cualquier intento de embargo o presión de acreedores externos sobre tu propiedad productiva.', 'Sin embargo, notamos que la base de activos tangibles no ha crecido, lo que sugiere un estancamiento en la modernización de tus herramientas de trabajo. Una consultora que no invierte en su propia infraestructura corre el riesgo de volverse obsoleta frente a competidores que están apalancando tecnología de punta para mejorar sus márgenes operativos.', 'Debes evaluar la adquisición de nuevas herramientas de software o hardware que eleven tu productividad. Aprovecha tu buena cobertura actual para solicitar financiamiento de fomento que sea barato y te permita modernizarte sin descapitalizar el negocio en este segundo bloque del año.', 'Bloque C - Trimestral 2Q 2023', 'antigravity', NOW()),
(3099, 'cobertura_fijos_3Q', 2023, 2023, '3Q', 'success', 'En este tercer periodo, la cobertura patrimonial de tus activos fijos se mantiene como tu baluarte de seguridad. Es gratificante ver que no has tenido que recurrir a pasivos onerosos para sostener tu base operativa, manteniendo una independencia estructural que es la envidia del sector de servicios profesionales hoy.', 'La alerta aquí es que tu patrimonio está siendo "subutilizado" si solo se limita a cubrir activos fijos que ya tienes depreciados. Estás manteniendo una solidez que no genera retornos adicionales. Tu estructura de fondeo es tan segura que ya raya en lo ineficiente desde el punto de vista puramente financiero de retorno sobre inversión.', 'Usa tu excelente cobertura para negociar mejores condiciones con tus proveedores estratégicos. Al no tener deudas sobre tus activos, eres un cliente de muy bajo riesgo que debería estar exigiendo plazos de pago mucho más largos y descuentos significativos que mejoren tu rentabilidad neta.', 'Bloque C - Trimestral 3Q 2023', 'antigravity', NOW()),
(3099, 'cobertura_fijos_4Q', 2023, 2023, '4Q', 'success', 'Cierras el año con una cobertura impecable. Has logrado que tu patrimonio sea el dueño absoluto de los activos fijos de la empresa, terminando el ciclo 2023 con una posición de solvencia técnica que garantiza la continuidad del negocio para el próximo año sin nubes de deuda en el horizonte.', 'El punto negativo es que el ratio no mostró una tendencia creciente apreciable. Has mantenido el status quo pero no has fortalecido la base de activos fijos netos de la compañía. Se percibe una actitud defensiva que, si bien es segura, podría frenar tu capacidad de escala estratégica para los retos del 2024.', 'Para el próximo año, tu meta debe ser que la cobertura de activos fijos supere el 1.2x. Necesitas que tu patrimonio crezca más rápido que tu depreciación para asegurar que siempre tengas la capacidad de renovar tu oficina y tecnología sin pedirle permiso al banco.', 'Bloque C - Trimestral 4Q 2023', 'antigravity', NOW())
INSERT INTO insights (empresa_id, indicador_key, periodo_ano, year, period_key, tipo, analisis_positivo, analisis_negativo, recomendacion, metodologia, generado_por, created_at)
VALUES 
(3099, 'estructura_deuda_1Q', 2023, 2023, '1Q', 'success', 'Iniciaste el 2023 con una estructura de pasivos sumamente liviana, sin registrar deudas de corto plazo que comprometan tu flujo de efectivo inmediato. Es admirable el control que tienes sobre tus obligaciones corrientes, permitiéndote navegar este inicio de año con una agilidad operativa total y sin presiones de tesorería.', 'No obstante, esta falta de deuda financiera estructurada te priva de construir un historial crediticio empresarial sólido desde temprano. Los bancos no ven movimiento en tus líneas de crédito, lo que podría dificultar que te otorguen montos significativos cuando realmente los necesites para una oportunidad de expansión rápida.', 'Te sugiero que abras una línea de crédito rotativo de bajo monto y la uses para gastos menores, pagándola siempre a tiempo. El objetivo no es obtener capital, sino "entrenar" tu balance para que sea atractivo ante el sistema financiero de cara a tus metas de largo plazo.', 'Bloque C - Trimestral 1Q 2023', 'antigravity', NOW()),
(3099, 'estructura_deuda_2Q', 2023, 2023, '2Q', 'success', 'Lograste mantener una estructura de deuda técnica en niveles mínimos durante este segundo trimestre. Tus pasivos están compuestos mayoritariamente por obligaciones operativas normales, lo que indica que estás financiando tu crecimiento con las mismas ventas del negocio y no con capitales externos costosos y riesgosos.', 'El riesgo latente es que tu estructura sea "demasiado simple". Al no tener deudas a largo plazo, cualquier necesidad de capital grande te obligaría a descapitalizarte rápidamente o a tomar deudas de emergencia con tasas muy altas. Estás viviendo financieramente al día, aunque con un balance muy limpio y honesto.', 'Evalúa la posibilidad de estructurar una deuda de largo plazo para la adquisición de un activo estratégico. Debes empezar a balancear tu composición de pasivos para que el 30% sea de largo plazo, dándote un respiro mayor en tus indicadores de cobertura de servicio de deuda trimestral.', 'Bloque C - Trimestral 2Q 2023', 'antigravity', NOW()),
(3099, 'estructura_deuda_3Q', 2023, 2023, '3Q', 'success', 'A mitad de este tercer bloque, tu estructura de deuda sigue siendo un modelo de prudencia. Has evitado por completo el sobreendeudamiento comercial, manteniendo una relación muy sana con tus proveedores estratégicos que confían plenamente en tu capacidad de pago oportuno por la limpieza de tu balance actual.', 'La nota negativa es que tu estructura de pasivos no registra deudas que generen beneficios de escudo fiscal. Estás perdiendo eficiencia en el pago de impuestos al no tener gastos financieros deducibles que optimicen tu utilidad neta final. En consultoría corporativa, la eficiencia fiscal es clave para maximizar tu patrimonio propio.', 'Conversa con tu equipo contable sobre cómo introducir una deuda estructurada que mejore tu perfil fiscal. No se trata de gastar más en intereses, sino de que esos intereses trabajen a tu favor reduciendo la carga impositiva mientras liberas capital propio para inversiones de mayor rentabilidad.', 'Bloque C - Trimestral 3Q 2023', 'antigravity', NOW()),
(3099, 'estructura_deuda_4Q', 2023, 2023, '4Q', 'success', 'Cierras el año con una estructura de pasivos impecable. Has demostrado que sabes operar una consultora de servicios profesionales de alto nivel sin depender de las muletas del crédito bancario tradicional, lo que te posiciona como un dueño de negocio independiente y con un control absoluto sobre su destino.', 'A pesar del éxito, vemos que tu falta de deuda de largo plazo te obliga a ser extremadamente conservador en tus proyecciones de crecimiento para el 2024. Tu estructura es segura pero le falta "músculo expansivo". Estás limitado a crecer solo al ritmo que tus utilidades retenidas te permitan, lo cual puede ser lento.', 'Para el 2024, tu meta debe ser diversificar tus fuentes de fondeo. Busca introducir un crédito de fomento o una línea de inversión que te dé la velocidad que hoy tu balance, por ser tan precavido, está conteniendo innecesariamente. Es hora de dejar de ser solo solvente para empezar a ser ambicioso.', 'Bloque C - Trimestral 4Q 2023', 'antigravity', NOW())
INSERT INTO insights (empresa_id, indicador_key, periodo_ano, year, period_key, tipo, analisis_positivo, analisis_negativo, recomendacion, metodologia, generado_por, created_at)
VALUES 
(3099, 'multiplicador_capital_1Q', 2023, 2023, '1Q', 'success', 'En el primer cuarto del año, tu multiplicador de capital se ubica en un envidiable 1.5x. Esto indica que mantienes un apalancamiento preventivo muy superior al promedio del sector, donde por cada peso propio solo tienes 0.50 pesos en deuda de terceros. Tienes un balance de acero para este inicio de ciclo.', 'La alerta aquí es el costo de capital propio. Al no usar deuda barata, podrías estar pagando una rentabilidad mayor a tus socios de lo que te costaría un crédito bancario eficiente. Tu estructura es muy segura, pero quizás un poco perezosa en términos de optimización del costo promedio ponderado de capital (WACC).', 'Te recomiendo que evalúes subir levemente este multiplicador hasta 1.7x usando crédito de fomento para inversiones tecnológicas. Debes aprender a usar el dinero ajeno para potenciar tus márgenes operativos sin sacrificar la seguridad patrimonial que ya has garantizado para este cierre de trimestre.', 'Bloque C - Trimestral 1Q 2023', 'antigravity', NOW()),
(3099, 'multiplicador_capital_2Q', 2023, 2023, '2Q', 'success', 'Llegamos a mitad de año con un multiplicador estable de 1.5x. Es muy positivo ver que no has caído en la tentación del sobreendeudamiento comercial, manteniendo una estructura de fondeo que es coherente con tu volumen de facturación actual. Eres dueño absoluto de tu ritmo de crecimiento patrimonial.', 'Sin embargo, este nivel de apalancamiento tan bajo sugiere que estás perdiendo oportunidades de escala rápida por evitar el crédito externo. Si el mercado te ofrece una oportunidad de compra masiva o un proyecto corporativo grande, tu estructura actual te obligaría a ser lento o a rechazarla por falta de fondos inmediatos.', 'Asegúrate de tener pre-aprobadas líneas de crédito de inversión aunque no las uses. Necesitas que tu multiplicador tenga la flexibilidad de subir temporalmente hasta 2.0x ante una oportunidad comercial irrepetible. No dejes que el miedo a la deuda te vuelva un espectador pasivo en un mercado que exige velocidad.', 'Bloque C - Trimestral 2Q 2023', 'antigravity', NOW()),
(3099, 'multiplicador_capital_3Q', 2023, 2023, '3Q', 'success', 'En este tercer periodo, el multiplicador de capital se mantiene en el corredor de excelencia (1.5x). Has demostrado una disciplina notable para no inflar tu balance con pasivos innecesarios, lo que garantiza que el negocio siga siendo fiel a su visión original de independencia y solvencia patrimonial estratégica.', 'El riesgo latente es que tu ROE (Retorno sobre el Patrimonio) esté estancado. Estás asumiendo todo el riesgo financiero sobre tus hombros sin compartirlo con acreedores externos. Si ocurriera una crisis, tu patrimonio recibiría el golpe directo sin amortiguadores financieros que "suavicen" el impacto en tus utilidades acumuladas en estos meses.', 'Te aconsejo que proyectes un cierre de año con un multiplicador de 1.6x destinado a mejorar tu infraestructura de servicios. Debes reinvertir en la capacidad de tu equipo humano para que el valor de tus activos intangibles crezca a la par de tu robustez financiera contable actual.', 'Bloque C - Trimestral 3Q 2023', 'antigravity', NOW()),
(3099, 'multiplicador_capital_4Q', 2023, 2023, '4Q', 'success', 'Terminas el 2023 con un multiplicador de capital de 1.5x, confirmando tu consistencia como gestor financiero. Tienes la mezcla ideal de fondeo para una consultora que busca estabilidad a largo plazo, brindando una tranquilidad absoluta a todos tus socios y acreedores estratégicos sobre la solvencia del negocio.', 'No obstante, esa constancia puede interpretarse como falta de ambición expansiva. Tu balance no refleja movimientos audaces de inversión financiada, lo que podría indicar que estás en una meseta de crecimiento. En finanzas corporativas, el apalancamiento moderado es el motor que separa a las empresas grandes de las eternamente medianas.', 'Para el 2024, atrévete a disparar tu multiplicador hasta 1.8x con deudas orientadas exclusivamente a proyectos de alto retorno esperado. Debes aprender a convivir con un nivel de pasivo que sea productivo y no solo que sea bajo por inercia administrativa. Es momento de liderar con solvencia y agresividad comercial.', 'Bloque C - Trimestral 4Q 2023', 'antigravity', NOW())
INSERT INTO insights (empresa_id, indicador_key, periodo_ano, year, period_key, tipo, analisis_positivo, analisis_negativo, recomendacion, metodologia, generado_por, created_at)
VALUES 
(3099, 'capitalizacion_1Q', 2023, 2023, '1Q', 'success', 'Tu ratio de capitalización en este inicio de 2023 es un ejemplo de solidez pura. Al no registrar deudas de largo plazo significativas, todo tu respaldo estructural proviene de recursos propios, lo que te garantiza una autonomía total en la toma de decisiones estratégicas frente a socios potenciales externos.', 'El aspecto negativo es que tu falta de deuda de largo plazo te priva de estructurar amortizaciones que sincronicen con tus ciclos de facturación anual. Estás viviendo de ingresos residuales, lo que obliga al negocio a ser muy conservador con sus flujos de caja operativos para no comprometer el patrimonio en el corto plazo.', 'Diferencia claramente tu capital propio de tus flujos operativos. Debes asegurar que al menos el 20% de tus utilidades actuales queden atrapadas en la reserva legal de la empresa para seguir fortaleciendo este indicador de forma orgánica y sin depender nunca de capitales externos arriesgados.', 'Bloque C - Trimestral 1Q 2023', 'antigravity', NOW()),
(3099, 'capitalizacion_2Q', 2023, 2023, '2Q', 'success', 'Mantenemos un ratio de capitalización impecable al cierre de este segundo bloque. Tu patrimonio sigue siendo el dueño único del destino financiero de la compañía, brindando una coraza protectora contra la subida de tasas de interés que está castigando a empresas que prefirieron fondearse irresponsablemente con terceros externos.', 'Sin embargo, esa capitalización tan alta por falta de pasivos de largo plazo le quita dinamismo a tu balance corporativo. Estás perdiendo el beneficio de la indexación de deuda, donde en economías inflacionarias una deuda de largo plazo fija te ayudaría a reducir el peso relativo de tus obligaciones mientras el negocio crece.', 'Busca asesoría para tomar una obligación bancaria de largo plazo que sea para fortalecimiento de marca. No esperes a necesitar el dinero; tómalo ahora que tu capitalización te da un poder de negociación enorme ante los bancos para obtener las tasas más bajas del mercado financiero en este año.', 'Bloque C - Trimestral 2Q 2023', 'antigravity', NOW()),
(3099, 'capitalizacion_3Q', 2023, 2023, '3Q', 'success', 'Llegamos al tercer trimestre con una capitalización envidiable. Tu balance contable refleja una salud patrimonial que muy pocas empresas del sector exhiben al final de este periodo, garantizando que el control total de la visión estratégica del negocio consultor siga plenamente en tus manos sin interferencias.', 'La nota de precaución es que tu ratio de capitalización es "estéril". Se mantiene bajo porque no hay deuda, pero tampoco hay un aumento vertiginoso del patrimonio por utilidades retenidas. Estás manteniendo la proporción correcta pero el volumen total de riqueza neta de la compañía no está escalando a la velocidad deseada.', 'Te sugiero que establezcas metas de retención de utilidades más ambiciosas para este cierre de año. Busca que tu capitalización siga siendo baja por falta de deuda, pero alta por el crecimiento real del valor de mercado de tus acciones propias. Debes convertir la solvencia en una creación de valor constante.', 'Bloque C - Trimestral 3Q 2023', 'antigravity', NOW()),
(3099, 'capitalizacion_4Q', 2023, 2023, '4Q', 'success', 'Cierre de año con una capitalización magistral. Has logrado atravesar todo el 2023 manteniendo una estructura de fondeo de largo plazo 100% propia, posicionándote para un 2024 donde tu capacidad de endeudamiento táctico será tu arma más potente para consolidar tu liderazgo en el mercado consultor regional.', 'El riesgo final de este ciclo es la baja utilización de tu escudo fiscal patrimonial. Estás dejando dinero sobre la mesa al no tener gastos financieros que reduzcan tu base impositiva de manera legal y ética. Tu estructura es segura, pero financieramente estás siendo más generoso con el fisco de lo que deberías ser en este periodo.', 'Para el 2024, introduce una "deuda de honor" a largo plazo con tasas preferenciales. Usa ese apalancamiento para modernizar tus procesos internos y asegura que tu capitalización siga siendo tu estándar de excelencia. No permitas que la comodidad de no deberle a nadie te quite la visión de optimización tributaria total.', 'Bloque C - Trimestral 4Q 2023', 'antigravity', NOW())
INSERT INTO insights (empresa_id, indicador_key, periodo_ano, year, period_key, tipo, analisis_positivo, analisis_negativo, recomendacion, metodologia, generado_por, created_at)
VALUES 
(3099, 'deuda_tangibles_1Q', 2023, 2023, '1Q', 'success', 'Al iniciar el año, tu deuda sobre activos tangibles es de solo 0.50x, lo que indica que tienes un respaldo físico muy superior a tus compromisos externos. Es una posición de seguridad técnica envidiable que te permite operar con la tranquilidad de que tus equipos y oficinas son realmente tuyos y no del banco.', 'Sin embargo, notamos que tu base de activos tangibles no ha sido evaluada comercialmente en mucho tiempo. Corres el riesgo de que la depreciación contable esté castigando tu balance más de lo que la realidad del mercado dicta, lo que podría restarte capacidad de garantía real si decidieras solicitar un crédito de inversión grande.', 'Realiza un inventario físico y técnico detallado de todas tus herramientas de trabajo. Necesitas saber cuánto valen realmente tus activos hoy para poder apalancarlos con inteligencia en el futuro. No dejes que el valor en libros sea la única medida de tu verdadera fortaleza física patrimonial en este 2023.', 'Bloque C - Trimestral 1Q 2023', 'antigravity', NOW()),
(3099, 'deuda_tangibles_2Q', 2023, 2023, '2Q', 'success', 'Llegamos a mitad de año manteniendo un ratio de 0.50x entre deuda y activos tangibles. Has logrado equilibrar tus compras operativas con el respaldo físico de la compañía, evitando que el pasivo se desborde sobre el valor real de tu infraestructura corporativa en este segundo trimestre de gestión.', 'La alerta aquí es que gran parte de tus activos tangibles son equipos de tecnología de rápida obsolescencia. Si no renuevas tu base física, tu respaldo real ante acreedores empezará a evaporarse a medida que la tecnología pierda su valor de reventa. Te estás confiando en un respaldo que tiene fecha de vencimiento tecnológica.', 'Destina un porcentaje fijo de tus utilidades a la modernización de activos físicos. Debes buscar que tu base tangible siempre sea joven y valiosa en el mercado secundario. Esto te dará un brazo financiero mucho más fuerte para negociar condiciones crediticias de primer nivel en el futuro cercano.', 'Bloque C - Trimestral 2Q 2023', 'antigravity', NOW()),
(3099, 'deuda_tangibles_3Q', 2023, 2023, '3Q', 'success', 'En este tercer periodo, el ratio de deuda a activos tangibles sigue siendo ejemplar (0.50x). Has demostrado una disciplina notable para amortizar tus deudas comerciales a medida que los activos envejecen, manteniendo una salud estructural que es garantía de continuidad para todos tus socios estratégicos.', 'El punto negativo es que no hemos visto nuevas inversiones que "engrosen" el lado de los activos tangibles en tu balance. Estás operando con lo mínimo indispensable, lo que te quita "cuerpo" financiero frente a competidores que están construyendo balances mucho más pesados y robustos mediante la adquisición estratégica de activos productivos.', 'Usa tu excelente margen actual para adquirir un activo de larga duración que no se deprecie tan rápido, como una sede propia o software de core de negocio con licencia perpetua. Necesitas que tu balance tenga más "anclajes" físicos que soporten tu visión de crecimiento de largo aliento para el próximo trienio.', 'Bloque C - Trimestral 3Q 2023', 'antigravity', NOW()),
(3099, 'deuda_tangibles_4Q', 2023, 2023, '4Q', 'success', 'Cierre de año con una relación deuda-tangibles de 0.50x, consolidando tu reputación como un gestor prudente y conservador con el respaldo físico de la compañía. Has atravesado todo el 2023 con una base de activos que duplica tus deudas totales, lo que te posiciona como un cliente de riesgo mínimo absoluto.', 'No obstante, esa prudencia te ha impedido escalar tecnológicamente a la velocidad que tus clientes corporativos exigen. Te has centrado tanto en no deber que has descuidado la actualización de tus herramientas de vanguardia, lo que podría empezar a afectar la calidad percibida de tu servicio en el próximo año fiscal.', 'Para el 2024, tu meta debe ser invertir el 15% de tu patrimonio en nuevos activos tangibles de alto impacto operativo. No le temas a las deudas si estas vienen respaldadas por activos que mejoren tu eficiencia. Es hora de darle más peso y modernidad a tu balance general para cerrar con broche de oro.', 'Bloque C - Trimestral 4Q 2023', 'antigravity', NOW())
INSERT INTO insights (empresa_id, indicador_key, periodo_ano, year, period_key, tipo, analisis_positivo, analisis_negativo, recomendacion, metodologia, generado_por, created_at)
VALUES 
(3099, 'propiedad_autonomia_1Q', 2023, 2023, '1Q', 'success', 'Iniciaste el 2023 con una autonomía financiera magistral superior al 65%. Es un indicador de poder total: eres el dueño absoluto de tu destino empresarial y no tienes que rendir cuentas a acreedores financieros asfixiantes en este arranque de año tan importante para tu consolidación.', 'El lado negativo es que la falta de socios externos o deuda estructurada te priva de visiones críticas sobre tu gestión operativa. Estás en una "burbuja de autonomía" que puede volverse complaciente si no te impones retos financieros externos que te obliguen a ser más eficiente con cada peso de tu patrimonio.', 'Busca crear un consejo asesor externo que cuestione tu uso del capital propio. Necesitas que alguien te diga si estás siendo demasiado conservador con tu riqueza patrimonial. El objetivo es que la autonomía sea tu fuerza motriz para el crecimiento acelerado y no solo tu zona de confort administrativa.', 'Bloque C - Trimestral 1Q 2023', 'antigravity', NOW()),
(3099, 'propiedad_autonomia_2Q', 2023, 2023, '2Q', 'success', 'Llegamos a mitad de año con una autonomía inalterable cerca del 67%. Has logrado que los excedentes del negocio sigan fortaleciendo tu capital propio, creando una barrera de solvencia que te protege contra cualquier eventualidad del mercado que pueda afectar a empresas menos capitalizadas que la tuya.', 'Sin embargo, notamos que tu riqueza está excesivamente concentrada en este único negocio. Al ser tan autónomo, no estás diversificando el riesgo patrimonial. Si el sector sufre una caída drástica, todo tu esfuerzo financiero se vería comprometido por no haber compartido el riesgo con capitales de terceros en este ciclo.', 'Considera la reinversión de dividendos en activos fuera del core del negocio o en nuevas líneas de servicio que se financien parcialmente con deuda externa. El objetivo es que tu autonomía siga siendo alta, pero que tu exposición al riesgo operativo sea más equilibrada mediante una mezcla de fondeo inteligente.', 'Bloque C - Trimestral 2Q 2023', 'antigravity', NOW()),
(3099, 'propiedad_autonomia_3Q', 2023, 2023, '3Q', 'success', 'En este tercer trimestre, tu ratio de propiedad sigue siendo el estándar de oro de tu balance. Dos tercios de la empresa son 100% de los socios, lo que te otorga una resiliencia patrimonial que te permite negociar de tú a tú con los grandes jugadores del mercado sin mostrar debilidad estructural.', 'La alerta aquí es que esa autonomía está "subsidiando" la ineficiencia de algunos procesos. Al no tener la presión de una cuota bancaria grande, podrías estar permitiendo que los gastos operativos crezcan más de lo debido. Estás quemando capital propio en ineficiencias que un banco nunca te perdonaría en sus revisiones.', 'Impónte a ti mismo un "presupuesto de deuda ficticio". Actúa como si tuvieras que pagar intereses a un tercero y esa eficiencia que logres guárdala en un fondo de reserva patrimonial para inversiones futuras. No permitas que la tranquilidad de ser el dueño te quite el hambre de eficiencia operativa constante.', 'Bloque C - Trimestral 3Q 2023', 'antigravity', NOW()),
(3099, 'propiedad_autonomia_4Q', 2023, 2023, '4Q', 'success', 'Cierre anual con una autonomía financiera del 67%, consolidando un 2023 de soberanía total. Has demostrado que es posible escalar una consultora de servicios profesionales manteniendo el control absoluto de la visión y los recursos, lo que te posiciona como un líder financieramente independiente y muy solvente.', 'El punto negativo es el costo de oportunidad de no haber crecido más rápido aprovechando capital externo. Has preferido la seguridad a la velocidad, y en un entorno tan dinámico como el de los servicios, podrías estar dejando márgenes de mercado sobre la mesa que competidores más agresivos ya están empezando a capitalizar.', 'Para el 2024, tu meta debe ser mantener una autonomía mínima del 60% pero inyectando capital externo para proyectos de escala 5X. Ya demostraste que puedes ser solvente; ahora demuestra que puedes ser expansivo sin perder la esencia de control que hoy es tu marca registrada en el balance general.', 'Bloque C - Trimestral 4Q 2023', 'antigravity', NOW())
INSERT INTO insights (empresa_id, indicador_key, periodo_ano, year, period_key, tipo, analisis_positivo, analisis_negativo, recomendacion, metodologia, generado_por, created_at)
VALUES 
(3099, 'deuda_patrimonio_1Q', 2023, 2023, '1Q', 'success', 'Tu relación deuda a patrimonio de 0.50x en este primer trimestre es el reflejo de un balance sumamente saneado. Tienes dos veces más capital propio que deuda total, lo que te garantiza una capacidad de respuesta inmediata ante cualquier imprevisto financiero sin poner en riesgo la viabilidad del negocio.', 'No obstante, este ratio tan bajo puede ser interpretado como falta de confianza en los proyectos futuros. Pareciera que prefieres guardar el dinero bajo el colchón patrimonial en lugar de ponerlo a trabajar mediante un apalancamiento productivo que maximice el valor de la compañía en este inicio de año tan prometedor.', 'Te sugiero que definas un corredor de apalancamiento ideal entre 0.8x y 1.2x. Estar en este rango te permitiría ser mucho más agresivo comercialmente sin abandonar nunca los niveles de solvencia que hoy protegen tu tranquilidad personal y la de tus socios estratégicos en este periodo.', 'Bloque C - Trimestral 1Q 2023', 'antigravity', NOW()),
(3099, 'deuda_patrimonio_2Q', 2023, 2023, '2Q', 'success', 'Llegamos a mitad de año con una relación deuda-patrimonio inalterable. Has logrado que el crecimiento del pasivo operativo sea compensado perfectamente por la retención de utilidades, manteniendo una equilibrio estructural que es garantía de estabilidad para todos tus colaboradores y proveedores de confianza.', 'Sin embargo, notamos que tu patrimonio está "financiando" a tus clientes de manera gratuita. Tu solidez patrimonial está permitiendo que otros se demoren en pagarte, consumiendo tu riqueza neta sin generar un retorno financiero por esa mora administrativa. Estás siendo el banco gratuito de tus clientes corporativos.', 'Ajusta tus políticas de cobro de inmediato. No permitas que tu bajísima relación deuda-patrimonio sea la excusa para que tus clientes no te paguen a tiempo. Tu patrimonio es para tu crecimiento, no para subsidiar la operación de terceros que no te retribuyen esa solvencia con puntualidad de pago.', 'Bloque C - Trimestral 2Q 2023', 'antigravity', NOW()),
(3099, 'deuda_patrimonio_3Q', 2023, 2023, '3Q', 'success', 'En este tercer periodo, la relación deuda-patrimonio de 0.50x sigue siendo tu mejor escudo. Es una cifra que comunica confianza absoluta al mercado, permitiéndote negociar créditos de gran escala si decidieras comprarlos con el fin de diversificar tus servicios o expandirte a nuevas geografías de forma inmediata.', 'El punto de atención es que la inercia de este número tan bajo puede estancarte creativamente. Al no tener la presión de las deudas, podrías estar perdiendo el sentido de urgencia por innovar y optimizar costos. La "paz patrimonial" excesiva a veces adormece el instinto de competencia empresarial más agresivo.', 'Evalúa la toma de un crédito de inversión estructurado para este cierre de año. Tienes la espalda patrimonial suficiente para absorberlo y usarlo como combustible para un 2024 de crecimiento explosivo. No dejes que el éxito de tu solvencia se convierta en el techo de tu expansión comercial futura.', 'Bloque C - Trimestral 3Q 2023', 'antigravity', NOW()),
(3099, 'deuda_patrimonio_4Q', 2023, 2023, '4Q', 'success', 'Cerras el trienio de 2023 con una relación deuda-patrimonio de 0.50x, reafirmando tu compromiso con la solidez estructural. Es un balance de "oro" que te deja en una posición inigualable para negociar cualquier alianza estratégica en el 2024, con un respaldo patrimonial que garantiza tu libertad total como socio.', 'A pesar del éxito, vemos que no has aprovechado el apalancamiento para mejorar tu ROE (Retorno sobre Patrimonio). Tu rentabilidad final depende exclusivamente de tus márgenes operativos y no de tu eficiencia financiera. Estás operando con un solo motor cuando podrías tener dos trabajando a máxima potencia.', 'Para el 2024, tu reto es subir este indicador a un nivel de 0.9x mediante deuda productiva de largo plazo. Debes aprender a multiplicar el valor de tu capital propio usando recursos de terceros que tengan un costo inferior a tu tasa de retorno esperada. Es el paso necesario para pasar de ser solvente a ser un titán del sector.', 'Bloque C - Trimestral 4Q 2023', 'antigravity', NOW())
INSERT INTO insights (empresa_id, indicador_key, periodo_ano, year, period_key, tipo, analisis_positivo, analisis_negativo, recomendacion, metodologia, generado_por, created_at)
VALUES 
(3099, 'cobertura_fijos_1Q', 2024, 2024, '1Q', 'success', 'Inicias el 2024 manteniendo una cobertura de activos fijos superior al 1.0x. Es gratificante ver que, a pesar de la incertidumbre económica global, tu patrimonio sigue siendo el guardián de tu infraestructura tecnológica y física, permitiéndote operar con una independencia envidiable en este arranque de ciclo.', 'La alerta en este primer trimestre es el estancamiento de tu inversión física. Al no haber renovado equipos en el último semestre, tu cobertura es alta solo porque tus activos se están depreciando, no porque tu patrimonio esté creciendo vigorosamente. Estás protegiendo una infraestructura que cada día es un poco más vieja.', 'Destina un fondo de ahorro específico para la modernización de tu core técnico. No permitas que la comodidad de tener una cobertura 1:1 te impida ver que tu competencia está invirtiendo en IA y automatización que tú todavía no has integrado a tu balance operativo neta hoy.', 'Bloque C - Trimestral 1Q 2024', 'antigravity', NOW()),
(3099, 'cobertura_fijos_2Q', 2024, 2024, '2Q', 'warning', 'A mitad de año, lograste sostener el respaldo patrimonial de tus activos fijos, lo que es un hito considerando que estamos atravesando el periodo de mayor estrés financiero del 2024. Tu propiedad técnica no ha sido comprometida para cubrir baches de tesorería, manteniendo tu soberanía institucional básica intacta.', 'El riesgo es que este indicador está herido por la caída en la autonomía general (55%). Tu patrimonio total está retrocediendo, lo que deja a tus activos fijos con un colchón de seguridad mucho más delgado que hace seis meses. Estás operando al borde de tu capacidad de respaldo propio real.', 'Frena cualquier gasto administrativo que no sea vital para recuperar tu margen de solvencia. Necesitas que tu patrimonio vuelva a crecer para que la cobertura de activos fijos deje de ser una preocupación y vuelva a ser tu principal activo de negociación ante los bancos este semestre.', 'Bloque C - Trimestral 2Q 2024', 'antigravity', NOW()),
(3099, 'cobertura_fijos_3Q', 2024, 2024, '3Q', 'success', 'En este tercer periodo de 2024, vemos una recuperación notable en la cobertura de tus activos fijos. Has logrado canalizar utilidades retenidas hacia el fortalecimiento de tu capital, enviando una señal potente al mercado de que la fase crítica de la crisis ha quedado atrás y que tu solvencia vuelve a ser indestructible.', 'La nota negativa es que no hemos aprovechado esta recuperación para adquirir activos que diversifiquen tu base de ingresos. Sigues dependiendo de la misma infraestructura de siempre, lo que te quita agilidad para pivotar hacia nuevas líneas de consultoría que hoy el mercado institucional está demandando agresivamente.', 'Aprovecha tu renovada cobertura para solicitar un crédito de inversión a tasas preferenciales. Tienes el respaldo patrimonial para hacerlo sin riesgo excesivo; es el momento de comprar las herramientas que te permitirán dominar el 2025 desde una posición de vanguardia tecnológica absoluta hoy.', 'Bloque C - Trimestral 3Q 2024', 'antigravity', NOW()),
(3099, 'cobertura_fijos_4Q', 2024, 2024, '4Q', 'success', 'Cierras el 2024 con una cobertura de activos fijos magistral, superando el 1.2x. Has demostrado una resiliencia gerencial fuera de lo común, logrando que tu patrimonio crezca más rápido que tu depreciación técnica, garantizando que entres al próximo año con una base de propiedad totalmente libre y saneada.', 'El riesgo para el próximo ciclo es la complacencia financiera. Al tener una cobertura tan sólida, podrías descuidar la eficiencia en el uso de esos activos. Un activo pago pero subutilizado es una ineficiencia que castiga tus márgenes de utilidad neta final. Debes asegurar que cada equipo facture al máximo.', 'Diseña un plan de renovación de activos para el 2025 que priorice la alta productividad sobre la mera posesión. Tu meta debe ser que tu patrimonio no solo cubra tus activos, sino que sea el motor que los multiplique cada año. Entra al nuevo año con una mentalidad de expansión y eficiencia total.', 'Bloque C - Trimestral 4Q 2024', 'antigravity', NOW())
INSERT INTO insights (empresa_id, indicador_key, periodo_ano, year, period_key, tipo, analisis_positivo, analisis_negativo, recomendacion, metodologia, generado_por, created_at)
VALUES 
(3099, 'estructura_deuda_1Q', 2024, 2024, '1Q', 'success', 'Inicias el 2024 con una gestión de pasivos sumamente disciplinada, manteniendo tus compromisos operativos bajo control estricto. Has logrado navegar los primeros tres meses sin caer en la trampa del sobreendeudamiento, lo que te otorga una paz mental invaluable para enfocarte en vender consultoría de gran impacto comercial.', 'La alerta roja es la falta de diversificación en tus fuentes de fondeo. Sigues dependiendo excesivamente de líneas de corto plazo que podrían cerrarse si hay un cambio brusco en la política monetaria. Tu estructura es segura pero no es resiliente ante un shock de liquidez bancaria inesperado en este inicio de ciclo.', 'Inicia gestiones para perfilar al menos un 20% de tu deuda hacia el largo plazo de inmediato. Debes lograr que tu balance deje de vivir al día y empiece a proyectar un horizonte de pagos que coincida con la ejecución de tus contratos de consultoría más ambiciosos y duraderos este año.', 'Bloque C - Trimestral 1Q 2024', 'antigravity', NOW()),
(3099, 'estructura_deuda_2Q', 2024, 2024, '2Q', 'danger', 'Afortunadamente, conservas una comunicación abierta y honesta con tus proveedores principales, lo que hoy te permite negociar plazos adicionales sin que te corten el suministro operativo vital. Tu prestigio personal es lo único que hoy sostiene la operatividad del negocio ante la aguda crisis de liquidez que enfrentas.', 'Lo crítico es que tu estructura de deuda se ha vuelto cien por ciento de "supervivencia", con vencimientos diarios que asfixian tu capacidad de decisión estratégica. Estás atrapado en un ciclo de pagos asfixiantes que te quitan energía para la innovación, convirtiéndote más en un tesorero de emergencia que en un gerente líder.', 'Diseña hoy mismo un plan de desahogo de pasivos mediante la consolidación de deudas pequeñas en un solo compromiso a 12 meses. Necesitas limpiar tu horizonte de pagos inmediatos para que tu flujo de caja respire y tu mente vuelva a enfocarse en generar riqueza y no solo en pagar incendios bancarios.', 'Bloque C - Trimestral 2Q 2024', 'antigravity', NOW()),
(3099, 'estructura_deuda_3Q', 2024, 2024, '3Q', 'info', 'Has logrado estabilizar tu estructura de deuda tras el vendaval del segundo trimestre, evitando el colapso financiero total. Es admirable cómo has recuperado el control de tus deudas comerciales, priorizando las obligaciones que verdaderamente mueven la aguja operativa de tu firma consultora estratégica en esta etapa.', 'El riesgo persistente es que te has acostumbrado a operar con una estructura de deuda "de guerra", descuidando el financiamiento para el crecimiento futuro. No tienes líneas de crédito listas para la expansión, lo que te obligará a ser lento cuando las oportunidades vuelvan a tocar a tu puerta en el cierre de año.', 'Reabre las conversaciones con los bancos de fomento ahora que tu balance muestra signos de recuperación real. Debes asegurar líneas de inversión que se activen automáticamente ante nuevos contratos grandes, garantizando que la estructura de tu deuda sea un aliado y no una barrera para tu escala comercial nacional.', 'Bloque C - Trimestral 3Q 2024', 'antigravity', NOW()),
(3099, 'estructura_deuda_4Q', 2024, 2024, '4Q', 'success', 'Cierras el 2024 con una estructura de fondeo externa sumamente optimizada y diversificada. Has logrado convertir gran parte de tus pasivos estresados en obligaciones manejables, terminando el ciclo fiscal con una reputación crediticia fortalecida y un balance que es el reflejo de una gestión de crisis magistral y vencedora.', 'La nota de cautela es el descuido del escudo fiscal de tu deuda actual. Has sido tan eficiente pagando que ahora estás dejando de percibir los beneficios tributarios de gastos financieros planificados. En finanzas corporativas, la eficiencia total también implica saber cuándo y cuánto deber para pagar menos impuestos de ley.', 'Para el 2025, diseña una estructura de deuda que incluya un componente de inversión de largo plazo con beneficios tributarios específicos. Haz que tu pasivo trabaje para elevar tu utilidad neta final, convirtiendo tu capacidad crediticia en una herramienta de generación de valor patrimonial constante y equilibrada hoy día.', 'Bloque C - Trimestral 4Q 2024', 'antigravity', NOW())
INSERT INTO insights (empresa_id, indicador_key, periodo_ano, year, period_key, tipo, analisis_positivo, analisis_negativo, recomendacion, metodologia, generado_por, created_at)
VALUES 
(3099, 'multiplicador_capital_1Q', 2024, 2024, '1Q', 'success', 'Inicias el 2024 con un multiplicador de capital de 1.5x, manteniendo una estructura de fondeo sumamente segura y equilibrada. Esto indica que conservas el control mayoritario del negocio, protegiendo tu patrimonio personal de la volatilidad de las tasas de interés que hoy castigan a las empresas sobreendeudadas del sector.', 'El riesgo latente es que un multiplicador tan bajo sugiere una baja agresividad en la captación de nuevos mercados. Al no apalancarte, estás perdiendo velocidad frente a competidores que están pidiendo prestado a tasas controladas para invertir masivamente en marketing y expansión territorial en este trimestre estratégico.', 'Eleva marginalmente tu multiplicador hasta 1.7x invirtiendo en tu fuerza de ventas comercial inmediata. Debes aprender a usar el capital de terceros para potenciar tu ROI sin abandonar nunca los niveles de solvencia que hoy son tu principal activo de tranquilidad institucional frente a tus socios y acreedores.', 'Bloque C - Trimestral 1Q 2024', 'antigravity', NOW()),
(3099, 'multiplicador_capital_2Q', 2024, 2024, '2Q', 'danger', 'Todavía conservas la propiedad de tu capital, lo que te da el timón absoluto para decidir el futuro de la empresa a pesar del altísimo apalancamiento alcanzado en este periodo de crisis. Tienes el poder de veto sobre las decisiones críticas, lo cual es tu única garantía para pilotar esta tormenta con autonomía total.', 'Tu multiplicador se ha disparado a niveles de 1.8x, indicando que estás operando una estructura que ya no se asienta en tu riqueza propia, sino en la paciencia de tus acreedores externos. Estás en una zona de riesgo extremo donde cualquier caída adicional en tus ingresos podría diluir tu participación patrimonial rápidamente.', 'Frena de inmediato cualquier gasto que no tenga un retorno de caja en menos de 15 días. Debes adelgazar tu balance a marchas forzadas para que tu patrimonio vuelva a pesar más que tu deuda, recuperando la soberanía real que MAS CONSULTA requiere para no ser una esclava de sus deudores financieros hoy.', 'Bloque C - Trimestral 2Q 2024', 'antigravity', NOW()),
(3099, 'multiplicador_capital_3Q', 2024, 2024, '3Q', 'success', 'Vemos con agrado que el multiplicador de capital ha vuelto a descender hacia el corredor de seguridad (1.6x), demostrando que tu plan de choque patrimonial está funcionando con precisión quirúrgica. Has recuperado terreno sobre tu propia empresa, volviendo a ser el motor financiero principal de tu operación diaria.', 'El punto negativo es que la desinversión necesaria para bajar este ratio te ha dejado con una operación mucho más pequeña y defensiva que el año pasado. Has ganado seguridad pero has perdido escala, lo que te quita méritos de competitividad frente a firmas que lograron navegar el estrés sin encoger su alcance comercial.', 'Inyecta capital propio mediante el giro de utilidades acumuladas para subir el patrimonio neto sin aumentar la deuda. Necesitas que el multiplicador baje no porque debas menos, sino porque vales más. El objetivo es que tu patrimonio sea tan grande que el apalancamiento sea una elección estratégica y no una necesidad.', 'Bloque C - Trimestral 3Q 2024', 'antigravity', NOW()),
(3099, 'multiplicador_capital_4Q', 2024, 2024, '4Q', 'success', 'Cierre anual con un multiplicador de 1.5x, confirmando que has superado la prueba de fuego del 2024 con un balance fortalecido y resiliente. Tienes hoy una estructura de fondeo magistral que te permite entrar al 2025 con un poder de fuego financiero enorme para consolidar tu liderazgo en el sector consultoría nacional.', 'Sin embargo, este nivel de apalancamiento mínimo sugiere que no estás explotando debidamente tu capacidad de endeudamiento para proyectos de gran calado internacional. Estás operando al nivel local cuando tu balance ya te permite jugar en las grandes ligas continentales mediante un apalancamiento inteligente y bien estructurado por ley.', 'Para el 2025, tu meta debe ser usar un multiplicador de 1.9x destinado exclusivamente a la expansión hacia nuevos mercados regionales. Ya demostraste que puedes gestionar la crisis; ahora demuestra que puedes gestionar el éxito masivo usando recursos de terceros que potencien infinitamente tu riqueza patrimonial real hoy día.', 'Bloque C - Trimestral 4Q 2024', 'antigravity', NOW())
INSERT INTO insights (empresa_id, indicador_key, periodo_ano, year, period_key, tipo, analisis_positivo, analisis_negativo, recomendacion, metodologia, generado_por, created_at)
VALUES 
(3099, 'capitalizacion_1Q', 2024, 2024, '1Q', 'success', 'Tu ratio de capitalización en este inicio de año refleja una independencia total frente al crédito de largo plazo, lo que te brinda una libertad estratégica invaluable. Tu capital propio es el soberano absoluto del balance, dándote una autoridad financiera envidiable para negociar cualquier contrato sin presiones externas bancarias.', 'El aspecto negativo es que esta falta de deuda de largo plazo te priva de estructurar flujos que amorticen en los meses de mayor facturación. Estás viviendo de ingresos corrientes, lo cual vuelve a tu balance muy vulnerable ante cualquier retraso de un cliente principal que afecte tu reserva de caja inmediata de MAS CONSULTA.', 'Te aconsejo que formalices una reserva de capitalización de utilidades del 20% anual. Debes construir tu propio fondo de inversión interno que te permita financiar proyectos de 6 meses sin tocar tu bolsillo personal, garantizando que tu capitalización sea alta no por falta de deuda, sino por exceso de ahorro propio.', 'Bloque C - Trimestral 1Q 2024', 'antigravity', NOW()),
(3099, 'capitalizacion_2Q', 2024, 2024, '2Q', 'warning', 'A pesar del vendaval financiero, tu ratio de capitalización se mantiene estable, demostrando que tu núcleo de capital propio es sumamente resistente. No has tenido que diluir tu participación ni hipotecar tu futuro patrimonial de largo plazo para cubrir los baches del corto plazo, lo cual es una proeza gerencial digna de admirar.', 'Lo preocupante es que no has podido construir ni una sola reserva institucional nueva en estos tres meses, dejando a la empresa desnuda ante cualquier contingencia mayor en el cierre de semestre. Estás financiando la consultora únicamente con tus ahorros pasados, lo cual tiene un límite de tiempo si la facturación no se reactiva neta.', 'Busca inyectar aire fresco a tu capitalización mediante aportes de socios o líneas de fomento que tengan períodos de gracia amplios. No sigas consumiendo tu riqueza neta sin un plan de reposición inmediata; necesitas que tu capitalización sea tu escudo de protección y no solo tu último recurso de supervivencia corporativa.', 'Bloque C - Trimestral 2Q 2024', 'antigravity', NOW()),
(3099, 'capitalizacion_3Q', 2024, 2024, '3Q', 'success', 'Vemos una mejora notable en tu capitalización al cierre de este tercer trimestre, demostrando que has logrado retener utilidades operativas para sanear el balance consolidado. Has recuperado tu fuerza patrimonial antes de lo previsto, posicionándote para un cierre de año con una solvencia técnica que muy pocos competidores tienen hoy.', 'La alerta aquí es que esa capitalización es "estéril" si no se invierte en activos que generen nuevos flujos de ingresos. Estás acumulando capital por miedo, lo que te quita dinamismo comercial. El dinero guardado no produce consultoría; solo protege el pasado pero no garantiza que ganes la guerra comercial en el futuro cercano hoy.', 'Diseña un plan de inversión agresivo para el Q4 usando parte de este excedente de capitalización. Debes pasar de la fase defensiva a la fase expansiva de inmediato; usa tu solvencia como garantía para tomar deudas baratas que te permitan capturar contratos que hoy exigen un respaldo económico de primer nivel nacional.', 'Bloque C - Trimestral 3Q 2024', 'antigravity', NOW()),
(3099, 'capitalizacion_4Q', 2024, 2024, '4Q', 'success', 'Cierre anual con una capitalización impecable de 0.50x (deuda LP / total), consolidando un ciclo de aprendizaje y robustecimiento patrimonial extraordinario. Has demostrado ser un dueño que prioriza la salud de largo plazo del negocio sobre los retiros inmediatos, lo que te garantiza un 2025 de independencia comercial total.', 'El riesgo final es el bajo uso del apalancamiento para optimizar tu ROE. Eres muy seguro pero financieramente poco audaz. Tu capitalización es tan alta que podrías estar obteniendo rentabilidades mucho mayores si compartieras el riesgo con recursos de terceros a bajo costo financiero en este periodo fiscal de MAS CONSULTA.', 'Para el próximo año, tu reto es mantener el ratio en 0.4x pero duplicando tu base de activos mediante deudas de fomento tecnológico. Debes aprender a multiplicar tu riqueza usando el dinero ajeno con inteligencia gerencial; es el secreto de las grandes consultoras para escalar globalmente sin descapitalizar a sus socios hoy día.', 'Bloque C - Trimestral 4Q 2024', 'antigravity', NOW())
INSERT INTO insights (empresa_id, indicador_key, periodo_ano, year, period_key, tipo, analisis_positivo, analisis_negativo, recomendacion, metodologia, generado_por, created_at)
VALUES 
(3099, 'deuda_tangibles_1Q', 2024, 2024, '1Q', 'success', 'Al iniciar el 2024, tus activos físicos siguen representando un respaldo genuino frente a tus pasivos, manteniendo un ratio de 0.50x que te otorga credibilidad ante el sistema financiero. Posees propiedad real sobre tus equipos, lo que te permite operar sin el temor inmediato de embargos comerciales en este ciclo.', 'El riesgo es que la depreciación acumulada está erosionando el valor neto de tus activos fijos más rápido de lo que estás amortizando tus deudas operativas. Si no inviertes en renovación, pronto lo que debes pesará más que el valor de reventa de tus activos físicos, debilitando tu perfil de garantía real ante acreedores.', 'Realiza una tasación técnica de tus activos industriales y tecnológicos de inmediato. Necesitas saber el valor de mercado real de tu infraestructura para usarla como palanca en negociaciones de crédito de inversión. No te confíes solo en el valor en libros contables para medir tu fuerza física patrimonial hoy.', 'Bloque C - Trimestral 1Q 2024', 'antigravity', NOW()),
(3099, 'deuda_tangibles_2Q', 2024, 2024, '2Q', 'danger', 'Afortunadamente, tus activos físicos siguen presentes en el balance como tu última línea de defensa patrimonial en este cierre de semestre. Posees herramientas y equipos que, aunque estresados por la falta de renovación, constituyen la garantía mínima necesaria para que tus proveedores no corten el flujo de insumos operacionales.', 'El riesgo es extremo: tus deudas corporativas han superado el valor de mercado de tus activos físicos en este reporte trimestral por el aumento de pasivos de corto plazo. Básicamente, si tuvieras que liquidar la empresa mañana, tus activos tangibles no alcanzarían para cubrir tus deudas, quedando en insolvencia técnica.', 'Urge que apliques una política de desinversión de activos ociosos para liquidar tus pasivos financieros más onerosos de inmediato. Debes equilibrar la balanza patrimonial hoy mismo; tu meta es que tus activos vuelvan a ser superiores a lo que debes para recuperar la dignidad y la fuerza de tu balance corporativo.', 'Bloque C - Trimestral 2Q 2024', 'antigravity', NOW()),
(3099, 'deuda_tangibles_3Q', 2024, 2024, '3Q', 'info', 'Vemos con buenos ojos que has logrado estabilizar la relación deuda-tangibles tras los momentos críticos del semestre anterior. Has frenado el crecimiento de pasivos innecesarios, permitiendo que tu base física vuelva a respirar y actúe como un respaldo sólido ante los nuevos desafíos comerciales de este cierre de año.', 'La alerta es que no has inyectado tecnología nueva que eleve el valor intrínseco de tus activos tangibles este trimestre. Estás operando con una infraestructura obsoleta que te quita méritos de competitividad frente a firmas que hoy usan equipos de vanguardia para reducir sus costos marginales operativos en MAS CONSULTA.', 'Diseña un plan de renovación tecnológica de bajo costo mediante el leasing de equipos estratégicos. Debes asegurar que tu propiedad física no pierda valor de mercado por obsolescencia técnica; usa tu capacidad de deuda saneada para adquirir activos que verdaderamente te den escala y eficiencia hoy día neta.', 'Bloque C - Trimestral 3Q 2024', 'antigravity', NOW()),
(3099, 'deuda_tangibles_4Q', 2024, 2024, '4Q', 'success', 'Cierras el 2024 con activos físicos que respaldan totalmente tus obligaciones con terceros, dándote un margen de seguridad jurídica y comercial muy respetable. Eres una empresa con propiedad real sobre sus herramientas de trabajo, lo que te otorga una credibilidad inmediata ante cualquier proceso de debida diligencia de socios.', 'No obstante, el riesgo para el próximo ciclo es el bajo dinamismo de tu inversión en infraestructura. Tras el susto del segundo trimestre, pareces tener miedo de invertir en activos tangibles pesados. Al no crecer físicamente, estás limitando tu capacidad de volumen de servicio para los grandes contratos del 2025.', 'Destina el 15% de tus utilidades de cierre de año a la compra de activos tecnológicos de alta rotación. Debes asegurar que tu base tangible sea moderna, productiva y altamente líquida en el mercado secundario. Esto garantizará que tu respaldo patrimonial físico sea real y no solo un número frío contable.', 'Bloque C - Trimestral 4Q 2024', 'antigravity', NOW())
INSERT INTO insights (empresa_id, indicador_key, periodo_ano, year, period_key, tipo, analisis_positivo, analisis_negativo, recomendacion, metodologia, generado_por, created_at)
VALUES 
(3099, 'propiedad_autonomia_1Q', 2024, 2024, '1Q', 'success', 'Inicias el 2024 con una autonomía financiera magistral cerca del 65%. Es un indicador de poder estratégico: eres el dueño casi absoluto de tu destino empresarial y no tienes que rendir cuentas a acreedores asfixiantes en este arranque de año, permitiéndote tomar decisiones audaces con total libertad.', 'El lado negativo es que la falta de socios externos te priva de visiones críticas sobre la ineficiencia de algunos de tus gastos fijos actuales. Estás en una burbuja de autonomía que puede volverse complaciente si no te impones retos financieros externos que te obliguen a ser más estricto con cada peso propio.', 'Busca crear un consejo de administración asesor que cuestione tu uso del capital. Necesitas que alguien externo valide si estás siendo demasiado conservador o si estás perdiendo oportunidades de escala por no querer compartir una mínima porción de tu autonomía hoy para ganar un mercado diez veces mayor.', 'Bloque C - Trimestral 1Q 2024', 'antigravity', NOW()),
(3099, 'propiedad_autonomia_2Q', 2024, 2024, '2Q', 'warning', 'A pesar de la alta presión crediticia, mantienes el 55% de la propiedad neta de tu firma consultora estratégica a mitad de 2024. Este es un hito de resistencia gerencial: has evitado que la crisis te quite el control mayoritario del negocio, dándote todavía el poder de decisión sobre el futuro de MAS CONSULTA.', 'Lo preocupante es que tu autonomía financiera se ha degradado bruscamente frente al 67% con el que terminaste el año pasado. Has entregado una parte importante de tu patrimonio a deudas de supervivencia, lo que te quita margen de maniobra para negociar de tú a tú con los grandes jugadores del mercado nacional.', 'Céntrate en fortalecer tu base de capital propio mediante la capitalización de cualquier excedente operativo que logres generar este semestre inmediatamente. Debes volver a subir este ratio por encima del 60% para que tu empresa sea verdaderamente soberana otra vez y elimines la sombra de los acreedores externos.', 'Bloque C - Trimestral 2Q 2024', 'antigravity', NOW()),
(3099, 'propiedad_autonomia_3Q', 2024, 2024, '3Q', 'info', 'Vemos con agrado que has recuperado parte de tu autonomía financiera, situándote nuevamente sobre el 60% de propiedad total de tus activos. Has demostrado una tenacidad admirable para "recomprar" tu empresa con utilidades operativas, alejando el riesgo de dilución que enfrentabas al cierre del segundo trimestre de este año.', 'La alerta aquí es que tu autonomía sigue siendo reactiva y no estratégica. Estás recuperando control pero no estás atrayendo capital que inyecte velocidad a tu escalabilidad regional. A veces, ser el dueño único de un negocio mediano es menos rentable que ser el socio mayoritario de una firma multinacional expansiva.', 'Evalúa si es conveniente para la consultora ceder una franja mínima de autonomía a cambio de un apalancamiento de inversión que te permita dominar nuevos nichos. Ser el dueño total es magnífico, pero ser el líder del mercado nacional de consultoría técnica es el verdadero objetivo que debes perseguir hoy.', 'Bloque C - Trimestral 3Q 2024', 'antigravity', NOW()),
(3099, 'propiedad_autonomia_4Q', 2024, 2024, '4Q', 'success', 'Cierre anual con una autonomía financiera del 72%, superando incluso tus niveles pre-crisis del 2023. Has demostrado que es posible atravesar una tormenta financiera y salir con un control patrimonial mucho mayor de MAS CONSULTA, lo que te garantiza una soberanía total para ejecutar tu visión estratégica ganadora en el 2025.', 'El riesgo final de este ciclo es la complacencia propia. Tras recuperar la autonomía, podrías caer en la tentación de no optimizar más tus costos de capital. No permitas que la tranquilidad de ser el único dueño te quite el hambre de eficiencia; el balance impecable debe ser tu plataforma para la audacia comercial.', 'Inicia el 2025 con una meta de autonomía del 75% pero inyectando deudas de fomento que no diluyan tu propiedad neta. Debes aprender a convivir con recursos ajenos que multipliquen tu rentabilidad final; ya demostraste solidez, ahora demuestra agresividad en la conquista de nuevos mercados con tu capital protegido plenamente hoy.', 'Bloque C - Trimestral 4Q 2024', 'antigravity', NOW())
INSERT INTO insights (empresa_id, indicador_key, periodo_ano, year, period_key, tipo, analisis_positivo, analisis_negativo, recomendacion, metodologia, generado_por, created_at)
VALUES 
(3099, 'deuda_patrimonio_1Q', 2024, 2024, '1Q', 'success', 'Tu relación deuda a patrimonio de 0.50x al iniciar el 2024 es el reflejo de un balance sumamente saneado y preparado para el crecimiento. Tienes el doble de capital propio que de deuda total, lo que te garantiza una capacidad de respuesta inmediata ante cualquier imprevisto financiero sin poner en riesgo la viabilidad.', 'No obstante, este ratio tan bajo puede ser interpretado como una falta de confianza en los macro-proyectos que el mercado ofrece hoy. Te has centrado tanto en la seguridad que podrías estar dejando pasar oportunidades de compra de activos o carteras de clientes que requieren un apalancamiento productivo inteligente y controlado.', 'Define hoy mismo un corredor de apalancamiento ideal entre 0.8x y 1.2x para este primer semestre. Estar en este rango te permitiría ser mucho más agresivo comercialmente sin abandonar nunca los niveles de solvencia que hoy protegen tu tranquilidad personal y la de tus socios en MAS CONSULTA hoy día.', 'Bloque C - Trimestral 1Q 2024', 'antigravity', NOW()),
(3099, 'deuda_patrimonio_2Q', 2024, 2024, '2Q', 'danger', 'Afortunadamente, la consultora conserva la capacidad operativa mínima gracias a que tu capital neto sigue siendo positivo a pesar del vendaval financiero. Haber terminado este Q2 con solvencia técnica básica es tu única base sólida para planificar la reestructuración masiva que exige el mercado ante la caída de tus ingresos.', 'Tu nivel de deuda frente al patrimonio ha sobrepasado los límites de seguridad racional (1.8x), lo que indica una fragilidad operativa extrema. Estás "alquilando" tu operación a tus acreedores comerciales, lo que te quita méritos de solvencia y te mantiene en un perfil de riesgo corporativo intolerablemente alto para cualquier banco.', 'Haz un compromiso gerencial de no tomar un solo peso más de deuda hasta que logres bajar este ratio a la mitad de inmediato. Enfócate exclusivamente en el recaudo acelerado de facturas para inyectar liquidez y fortalecer tu base patrimonial desde adentro, recuperando la salud institucional que has perdido en este semestre.', 'Bloque C - Trimestral 2Q 2024', 'antigravity', NOW()),
(3099, 'deuda_patrimonio_3Q', 2024, 2024, '3Q', 'success', 'Vemos una corrección muy saludable en tu relación deuda-patrimonio (1.2x) al cierre de este tercer periodo, demostrando que has logrado amortizar pasivos asfixiantes. Tu patrimonio vuelve a ganar peso relativo en el balance, devolviéndote la credibilidad ante acreedores y socios que ya empezaban a dudar de tu solvencia técnica neta.', 'La nota negativa es que esta corrección se hizo a costa de reducir tu inventario operativo y tu base de activos. Has "encogido" la empresa para salvar la relación de deuda, lo que te deja con un menor músculo de ejecución para los grandes contratos de fin de año que exigen una capacidad técnica mayor.', 'Inyecta capital mediante la retención estricta del 50% de las utilidades de este trimestre de forma definitiva. Necesitas que el patrimonio crezca para que el ratio de deuda baje no porque debas menos, sino porque seas más grande y valioso; es el camino real para una solvencia que no sea solo defensiva.', 'Bloque C - Trimestral 3Q 2024', 'antigravity', NOW()),
(3099, 'deuda_patrimonio_4Q', 2024, 2024, '4Q', 'success', 'Cierre de año con una relación deuda-patrimonio magistral del 0.40x, superando con creces tus objetivos de solvencia originales del ciclo fiscal. Has logrado invertir la balanza de poder en tu balance, donde hoy tu patrimonio es 2.5 veces superior a tu deuda total en este reporte final de auditoría del 2024.', 'Vigila que esta fuerza patrimonial no se vea afectada por una repartición de dividendos demasiado agresiva al iniciar el 2025. Si descapitalizas la empresa ahora por un impulso personal de retiro de caja, podrías entrar al nuevo año con una fragilidad estructural que te quite poder de reacción ante nuevos contratos grandes.', 'Mantén la mayoría de las utilidades dentro del balance para iniciar el próximo ciclo con un músculo patrimonial histórico y ganador hoy mismo. Tu empresa ha demostrado ser una máquina de generar solvencia; no la debilites ahora que está en su mejor momento reputacional ante el mercado financiero colombiano neta.', 'Bloque C - Trimestral 4Q 2024', 'antigravity', NOW())
INSERT INTO insights (empresa_id, indicador_key, periodo_ano, year, period_key, tipo, analisis_positivo, analisis_negativo, recomendacion, metodologia, generado_por, created_at)
VALUES 
(3099, 'cobertura_fijos_1Q', 2025, 2025, '1Q', 'success', 'Inicias el 2025 con una transformación estructural sin precedentes, donde tu cobertura de activos fijos se ha disparado gracias a la inyección masiva de capital propio. Tienes un patrimonio tan robusto que hoy podrías comprar tu infraestructura operativa actual cinco veces con recursos propios, eliminando cualquier rastro de riesgo de propiedad.', 'El reto paradójico es la ineficiencia del capital ocioso. Tener un patrimonio tan inmenso cubriendo activos fijos que ya tienes pagados indica que no estás moviendo tu riqueza con la velocidad que el mercado corporativo exige. Estás sentado sobre una montaña de seguridad que no está generando nuevos contratos por sí sola.', 'Usa este nuevo músculo patrimonial para adquirir tecnología de punta y expandir tu presencia física en nuevas geografías de inmediato. Tienes el respaldo absoluto para ser el líder tecnológico del sector; no permitas que tu capital se convierta en una zona de confort institucional, sino en tu rampa de lanzamiento global hoy.', 'Bloque C - Trimestral 1Q 2025', 'antigravity', NOW()),
(3099, 'cobertura_fijos_2Q', 2025, 2025, '2Q', 'success', 'Llegamos a mitad de año con una cobertura patrimonial que es la envidia de cualquier tesorero corporativo. Has logrado que el crecimiento de tus activos fijos sea superado constantemente por la retención de tus utilidades récord, manteniendo una protección estructural que blinda a MAS CONSULTA contra cualquier volatilidad económica externa.', 'La nota de precaución es el potencial descuido del retorno sobre activos fijos (ROFA). Al estar tan "protegido", podrías estar permitiendo que la productividad de tus equipos baje. Un activo 100% propio que no factura su capacidad máxima es una pérdida de oportunidad financiera que castiga tu rentabilidad neta final acumulada.', 'Implementa un tablero de control de productividad por activo fijo de inmediato. Asegura que cada computadora, licencia o espacio de oficina genere al menos tres veces su costo de reposición. Tu meta es que la cobertura sea el resultado de un negocio altamente productivo y no solo de un balance contable estático.', 'Bloque C - Trimestral 2Q 2025', 'antigravity', NOW()),
(3099, 'cobertura_fijos_3Q', 2025, 2025, '3Q', 'success', 'En este tercer periodo de 2025, tu cobertura patrimonial sigue en la estratósfera financiera. Es gratificante ver cómo has construido una fortaleza indestructible que permite a tus socios dormir tranquilos, sabiendo que el control total de la infraestructura operativa reside exclusivamente en las manos de los fundadores y accionistas.', 'El riesgo latente es la falta de apalancamiento estratégico para misiones de escala 10X. Tienes tanto patrimonio cubriendo tus equipos que estás siendo demasiado "limpio" financieramente, perdiendo la oportunidad de usar recursos de terceros que hoy te saldrían casi gratis por tu calificación de riesgo AAA institucional neta.', 'Inicia la compra de activos pesados de consultoría (software de IA propia o sedes regionales) usando un mix de capital propio y deuda barata. Debes aprender a convivir con un nivel de pasivo productivo que no comprometa tu cobertura, pero que sí acelere tu ritmo de conquista de nuevos mercados nacionales e internacionales.', 'Bloque C - Trimestral 3Q 2025', 'antigravity', NOW()),
(3099, 'cobertura_fijos_4Q', 2025, 2025, '4Q', 'success', 'Cierras el trienio 2023-2025 con una cobertura de activos fijos magistral, consolidando una revolución patrimonial histórica en MAS CONSULTA. Has demostrado que es posible ser una firma de servicios líder manteniendo una solvencia técnica impecable, donde el patrimonio neto es el dueño soberano de cada tornillo y licencia de la empresa.', 'De cara al 2026, el riesgo es el estancamiento de la visión. Ya lograste la seguridad total; ahora el mercado te exigirá reinvención. Si te quedas solo contemplando tu magnífica cobertura, permitirás que competidores más ágiles te roben cuota de mercado mediante modelos de negocio mucho más livianos en activos físicos hoy.', 'Diseña la hoja de ruta estratégica para el próximo trienio priorizando la inversión en activos intangibles de alto valor (marca, patentes, algoritmos). Tu patrimonio debe ahora cubrir no solo lo que tocas, sino el conocimiento que generas. Es el paso final para pasar de ser una consultora sólida a ser una consultora legendaria.', 'Bloque C - Trimestral 4Q 2025', 'antigravity', NOW())
INSERT INTO insights (empresa_id, indicador_key, periodo_ano, year, period_key, tipo, analisis_positivo, analisis_negativo, recomendacion, metodologia, generado_por, created_at)
VALUES 
(3099, 'estructura_deuda_1Q', 2025, 2025, '1Q', 'success', 'Has logrado sanear tu estructura de pasivos de forma magistral en este arranque de 2025, eliminando definitivamente la asfixia del corto plazo que te robó el sueño el año anterior. Hoy tu deuda es equilibrada, predecible y está perfectamente sincronizada con tus ciclos de facturación récord, dándote una libertad operativa total.', 'Vigila que esta nueva comodidad crediticia no te lleve a relajar los procesos de control de gastos hormiga que tanto te costó organizar. El hecho de que hoy tengas liquidez de sobra para cubrir tus deudas no significa que debas permitir goteos de dinero en ineficiencias administrativas que erosionen tu utilidad neta en este semestre.', 'Aprovecha tu brillante calificación crediticia actual para renegociar las tasas de tus compromisos de largo plazo a la baja de inmediato. Tienes el sartén por el mango; haz valer tu nueva solvencia ante los bancos y conviértete en el cliente preferencial que todas las entidades quieren en su cartera comercial este año.', 'Bloque C - Trimestral 1Q 2025', 'antigravity', NOW()),
(3099, 'estructura_deuda_2Q', 2025, 2025, '2Q', 'success', 'Llegamos a mitad de 2025 con una estructura de deuda que es un modelo a seguir para el sector de servicios profesionales. Has logrado que tus pasivos operacionales sean financiados por utilidades corrientes, manteniendo un balance limpio de deudas tóxicas o de emergencia que comprometan tu futuro patrimonial institucional.', 'El riesgo potencial es "la deuda de oportunidad perdida". Al tener una estructura tan conservadora, podrías estar dejando de financiar proyectos de adquisición de competidores que hoy están baratos. Estás siendo tan ordenado que podrías estar volviéndote predecible y lento para las grandes movidas corporativas del mercado nacional.', 'Apertura una línea de crédito de "despliegue rápido" que solo se active para compras de carteras de clientes o talento sénior. Debes asegurar que tu estructura de deuda tenga la flexibilidad de crecer instantáneamente ante una oportunidad de mercado irrepetible, sin perder el orden que hoy es tu marca registrada.', 'Bloque C - Trimestral 2Q 2025', 'antigravity', NOW()),
(3099, 'estructura_deuda_3Q', 2025, 2025, '3Q', 'success', 'En este tercer periodo, tu estructura de pasivos refleja una salud financiera inmejorable. Has demostrado una disciplina notable para prepagar obligaciones costosas, terminando el ciclo con una mezcla de fondeo sumamente barata y eficiente que maximiza el valor final para todos los accionistas de MAS CONSULTA hoy.', 'La alerta aquí es la concentración de tus obligaciones en una sola entidad bancaria estratégica. Aunque hoy tienes excelentes términos, estás creando una dependencia que podría ser riesgosa si esa entidad cambia sus políticas comerciales. No permitas que tu orden estructural te ciegue ante la necesidad de diversificar a tus socios de fondeo.', 'Busca aperturar relaciones crediticias con un segundo banco de primer nivel este mes. Debes tener al menos dos fuentes de fondeo compitiendo por darte mejores tasas; usa tu impecable balance de 2025 como el trofeo que atraiga a los mejores postores del sistema financiero nacional a tu favor neta.', 'Bloque C - Trimestral 3Q 2025', 'antigravity', NOW()),
(3099, 'estructura_deuda_4Q', 2025, 2025, '4Q', 'success', 'Cierras el trienio con una estructura de deuda impecable y profesionalizada al 100%. Has pasado de ser un bombero de incendios financieros en el 2024 a ser un arquitecto de solvencia en el 2025, terminando el año con un pasivo que es apenas un susurro frente a la magnitud de tus ingresos y utilidades acumuladas.', 'Para el 2026, el riesgo es el exceso de holgura financiera. Cuando sobra el dinero en el balance, la disciplina de costos suele relajarse involuntariamente. Debes evitar que el éxito de tu saneamiento de deuda se convierta en la excusa para el derroche administrativo en el próximo arranque de ciclo fiscal neta hoy.', 'Implementa un presupuesto de "base cero" para el próximo año. No permitas que tus deudas bajen solo para que tus gastos administrativos suban; mantén la mentalidad de eficiencia que te sacó de la crisis y asegúrate de que tu estructura de deuda siga siendo tu ventaja competitiva invisible pero potente.', 'Bloque C - Trimestral 4Q 2025', 'antigravity', NOW())
INSERT INTO insights (empresa_id, indicador_key, periodo_ano, year, period_key, tipo, analisis_positivo, analisis_negativo, recomendacion, metodologia, generado_por, created_at)
VALUES 
(3099, 'multiplicador_capital_1Q', 2025, 2025, '1Q', 'success', 'Inicias el 2025 con un multiplicador de capital de 1.05x, devolviéndote el control indiscutible de tu firma tras la histórica restructuración patrimonial. Has pasado de ser un gerente acosado por deudas a ser un dueño soberano que opera con su propia fuerza económica, garantizando independencia total para tus decisiones.', 'Tener un multiplicador tan bajo indica que estás dejando de usar el apalancamiento inteligente que potencia los negocios de clase mundial. Si bien la seguridad es primordial tras la crisis, cerrar totalmente la puerta al crédito barato puede restarte velocidad frente a consorcios internacionales que operan con capital mixto agresivo.', 'Reinicia de inmediato una política de apalancamiento estratégico para financiar tus nuevos grandes contratos nacionales. Usa tu excelente solvencia para atraer recursos externos que multipliquen tu rentabilidad final; ya no necesitas el crédito para sobrevivir, ahora debes usarlo únicamente para ganar más dinero hoy día.', 'Bloque C - Trimestral 1Q 2025', 'antigravity', NOW()),
(3099, 'multiplicador_capital_2Q', 2025, 2025, '2Q', 'success', 'Llegamos a mitad de año con un multiplicador consolidado en niveles de excelencia (1.1x). Has demostrado una maestría única para equilibrar el crecimiento de tus utilidades con el control estricto del pasivo, manteniendo un balance que es el estándar de oro de la consultoría estratégica nacional hoy mismo.', 'El aspecto negativo es que tu ROE (Retorno sobre Patrimonio) está contenido. Al no usar deuda, tu rentabilidad neta depende exclusivamente de tu margen operativo. Estás perdiendo el efecto "multiplicador" que el dinero ajeno le daría a tu talento propio, obligando al patrimonio a hacer todo el esfuerzo solo.', 'Atrévete a subir este indicador hasta 1.4x mediante deudas destinadas exclusivamente a la innovación técnica de IA. Debes aprender a multiplicar el valor de tus acciones propias usando recursos de terceros que tengan un costo inferior a tu tasa de retorno esperada; es el paso necesario para ser un gigante regional.', 'Bloque C - Trimestral 2Q 2025', 'antigravity', NOW()),
(3099, 'multiplicador_capital_3Q', 2025, 2025, '3Q', 'success', 'En este tercer periodo, el multiplicador de capital sigue reflejando una salud patrimonial inigualable. Has construido una red de seguridad tan amplia que MAS CONSULTA es hoy inmune a las crisis de liquidez bancaria, permitiéndote negociar alianzas desde una posición de poder absoluto y soberanía financiera total.', 'La alerta aquí es el costo de oportunidad de tu capital propio. Al tenerlo todo en el balance, estás renunciando a diversificar ese riesgo en otros vehículos de inversión externos. Eres muy solvente pero quizás excesivamente conservador con la riqueza que has generado para tus socios fundadores este año fiscal.', 'Crea una política de dividendos audaz que premie el esfuerzo de capitalización hecho por los socios. Tienes la espalda financiera para retirar utilidades sin comprometer tu multiplicador de capital; es hora de que la solvencia del negocio se traduzca en una creación de riqueza tangible para sus dueños reales.', 'Bloque C - Trimestral 3Q 2025', 'antigravity', NOW()),
(3099, 'multiplicador_capital_4Q', 2025, 2025, '4Q', 'success', 'Cierre de ciclo con un multiplicador de 1.1x, coronando un trienio de transformación financiera impecable. Has demostrado al mercado y a tus competidores que MAS CONSULTA es una firma con cimientos de acero, capaz de autofinanciar su liderazgo y proyectar un crecimiento soberano para los próximos cinco años de gestión.', 'Para el 2026, el reto es no permitir que la seguridad se convielta en inacción. Tu multiplicador es tan bajo que hoy eres un "banco propio", y eso exige una gestión de activos mucho más dinámica de lo que has mostrado hasta hoy. Debes evitar que tu balance se vuelva una foto estática de éxito pasado hoy.', 'Inicia el próximo año con una meta de apalancamiento inteligente del 30% destinado a la expansión global. Tienes el patrimonio limpio; ahora úsalo como garantía para dominar nuevos mercados en el continente. El objetivo es que tu multiplicador crezca porque tu ambición creció y no porque tu caja se agotó neta.', 'Bloque C - Trimestral 4Q 2025', 'antigravity', NOW())
INSERT INTO insights (empresa_id, indicador_key, periodo_ano, year, period_key, tipo, analisis_positivo, analisis_negativo, recomendacion, metodologia, generado_por, created_at)
VALUES 
(3099, 'capitalizacion_1Q', 2025, 2025, '1Q', 'success', 'La capitalización masiva que ha experimentado MAS CONSULTA en este arranque de 2025 es un hito de solvencia para todo el sector de servicios. Has logrado blindar el largo plazo de la empresa con reservas propias que garantizan su supervivencia por décadas, dándote una autoridad financiera que te permite liderar cualquier mesa hoy.', 'Cuidado con la tentación de repartir dividendos excesivos ahora que el balance se ve tan saludable y lleno de capital tras la histórica inyección del trimestre. Si descapitalizas el negocio tan pronto, podrías perder la ventana de oportunidad histórica que tienes para comprar competidores pequeños que hoy están baratos.', 'Establece una política formal de reinversión del 60% de tus utilidades netas mensuales de forma inmediata. Tu empresa hoy es una fortaleza indestructible; mantén ese escudo levantado para que el 2025 sea recordado como el año en que MAS CONSULTA se convirtió en un gigante patrimonial indestructible nacional.', 'Bloque C - Trimestral 1Q 2025', 'antigravity', NOW()),
(3099, 'capitalizacion_2Q', 2025, 2025, '2Q', 'success', 'Llegamos a mitad de 2025 con un ratio de capitalización (deuda LP / total) que confirma tu independencia absoluta frente al crédito bancario asfixiante. Tu capital propio es el que dicta el ritmo de las inversiones tecnológicas, permitiéndote una agilidad comercial que tus competidores endeudados desearían tener hoy mismo.', 'El riesgo es la falta de una visión financiera "de largo aliento" que acompañe tus ambiciones globales. Al no tener deudas de fomento a 5 o 10 años, toda tu operación pende de la retención constante de flujos, lo que podría generarte un estrés innecesario si ocurre un retraso fortuito en tus grandes cobros hoy.', 'Apertura una línea de crédito de fomento para grandes consultoras con un periodo de gracia amplio. No lo hagas por necesidad, sino por estrategia: tener capital externo de largo plazo te da una estabilidad que te permite planificar adquisiciones de infraestructura sin tocar tu reserva de caja operativa diaria neta.', 'Bloque C - Trimestral 2Q 2025', 'antigravity', NOW()),
(3099, 'capitalizacion_3Q', 2025, 2025, '3Q', 'success', 'En el tercer trimestre, tu capitalización de utilidades ha alcanzado niveles récord, consolidando una red de seguridad patrimonial que es garantía de continuidad perpetua. Posees una autonomía estratégica total para pivotar tu modelo de negocio o invertir en nuevas líneas de IA sin pedir permiso a ninguna junta de acreedores hoy.', 'La alerta aquí es la ineficiencia fiscal de tu altísima capitalización propia. Al no registrar gastos financieros de largo plazo, tu base imponible es máxima, lo que te obliga a ser más generoso con el fisco de lo que una planificación financiera moderadamente apalancada sugeriría para una empresa de tu tamaño corporativo neta.', 'Consulta con tu asesor tributario sobre cómo estructurar una deuda de largo plazo que optimice tu carga impositiva. Usa el apalancamiento no para pedir dinero, sino para pagar menos impuestos mientras sigues fortaleciendo tu capital propio con esos ahorros fiscales; es la jugada de ajedrez financiero que hoy necesitas.', 'Bloque C - Trimestral 3Q 2025', 'antigravity', NOW()),
(3099, 'capitalizacion_4Q', 2025, 2025, '4Q', 'success', 'Cierras el 2024 con una capitalización histórica que te posiciona como el líder indiscutible de solvencia en el mercado colombiano de servicios profesionales. Has terminado el trienio transformando tu balance de un estado de alerta roja a un estado de soberanía total, garantizando un 2026 de dominio comercial absoluto neta.', 'De cara al futuro, el riesgo es el estancamiento de la rentabilidad patrimonial. Estás tan capitalizado que tu ROE es naturalmente bajo. Debes demostrar que ese enorme capital no es solo un refugio contra el miedo, sino una herramienta de ataque masivo para capturar los contratos más rentables del continente el próximo año.', 'Destina el 20% de tu capital excedente a un fondo de innovación disruptiva. Usa tu fuerza de balance para crear servicios que hoy nadie ofrece en el mercado; ya tienes la solidez, ahora te toca usarla para revolucionar la industria de la consultoría desde tu posición de poder patrimonial indestructible diaria.', 'Bloque C - Trimestral 4Q 2025', 'antigravity', NOW())
INSERT INTO insights (empresa_id, indicador_key, periodo_ano, year, period_key, tipo, analisis_positivo, analisis_negativo, recomendacion, metodología, generado_por, created_at)
VALUES 
(3099, 'deuda_tangibles_1Q', 2025, 2025, '1Q', 'success', 'Al iniciar el 2025, tu relación de deuda sobre activos tangibles es prácticamente inexistente, lo que te otorga una solvencia física absoluta. Has logrado que cada equipo y herramienta de MAS CONSULTA sea propiedad neta de los socios, eliminando cualquier sombra de embargo o restricción operativa por parte de acreedores externos hoy.', 'El riesgo paradójico es que tus activos tangibles se están volviendo "viejos" en términos contables y tecnológicos. Al no usar deuda para renovarlos, estás permitiendo que tu infraestructura pierda valor de mercado por obsolescencia, lo que podría restarte competitividad ante nuevas licitaciones que exijan tecnología de punta neta.', 'Inicia un plan de renovación de infraestructura técnica usando el 10% de tu excedente de capitalización de este trimestre. No necesitas endeudarte; tienes la fuerza para comprar lo mejor del mercado al contado, asegurando que tu respaldo tangible sea moderno, eficiente y altamente productivo de inmediato hoy día.', 'Bloque C - Trimestral 1Q 2025', 'antigravity', NOW()),
(3099, 'deuda_tangibles_2Q', 2025, 2025, '2Q', 'success', 'Llegamos a mitad de año con activos físicos que son el pilar de una solvencia indestructible. Has demostrado que es posible escalar una firma de consultoría manteniendo la propiedad total de sus herramientas de producción, lo que te brinda una credibilidad excepcional ante cualquier socio estratégico o inversionista global neta.', 'La nota de cautela es la baja rotación de tus activos tangibles. Tienes equipos que ya cumplieron su ciclo de vida productivo pero que siguen en el balance por "limpieza" financiera. Mantener activos obsoletos es una forma de ineficiencia que castiga tus márgenes brutos debido a mayores costos de mantenimiento y menor velocidad neta.', 'Ejecuta un plan de chatarrización o venta de activos antiguos de forma inmediata. Debes limpiar tu balance de todo lo que no sume valor operativo real; quédate solo con lo que te haga más rápido y eficiente. Tu meta es tener una base tangible liviana pero sumamente potente para el cierre de semestre hoy mismo.', 'Bloque C - Trimestral 2Q 2025', 'antigravity', NOW()),
(3099, 'deuda_tangibles_3Q', 2025, 2025, '3Q', 'success', 'En el tercer periodo, tu respaldo físico patrimonial sigue siendo un escudo de protección inexpugnable. Has logrado que MAS CONSULTA sea una empresa con "raíces de acero", donde el patrimonio neto cubre con creces cualquier fluctuación en la valoración de mercado de tus activos operativos pesados y tecnológicos hoy.', 'El riesgo es que no estás aprovechando este colosal respaldo físico para apalancarte en proyectos de infraestructura masiva. Estás operando con el freno de mano puesto en cuanto a inversión física se refiere, lo que podría limitar tu capacidad de atender a grandes multinacionales que exigen sedes y tecnología de escala continental.', 'Evalúa el leasing de una nueva sede corporativa inteligente o un centro de datos propio este mes. Tienes el respaldo tangible para obtener las mejores tasas del mercado; usa tu propiedad actual como garantía para dar el salto hacia una infraestructura de clase mundial que te posicione como el líder absoluto neta.', 'Bloque C - Trimestral 3Q 2025', 'antigravity', NOW()),
(3099, 'deuda_tangibles_4Q', 2025, 2025, '4Q', 'success', 'Cierras el trienio 2023-2025 con una relación deuda-tangibles ejemplar, consolidando un balance que es el reflejo de una gestión de activos magistral. Has terminado el año con una infraestructura operativa 100% propia y saneada, garantizando una libertad de acción total para los ambiciosos retos de expansión del próximo ciclo.', 'Para el 2026, el reto es mantener la agilidad física. El mundo de la consultoría se mueve hacia activos intangibles y modelos "asset-light". No te enamores de tus activos fijos; asegúrate de que tu patrimonio los cubra pero que no te aten a modelos de negocio estáticos que te quiten velocidad de respuesta hoy.', 'Diseña una estructura de activos para el próximo trienio que priorice la flexibilidad y la movilidad tecnológica. Tu base tangible debe ser el soporte de tu conocimiento, no una carga que te impida pivotar hacia nuevas oportunidades digitales globales. Mantén la solvencia pero aumenta la agilidad física de inmediato neta.', 'Bloque C - Trimestral 4Q 2025', 'antigravity', NOW())
INSERT INTO insights (empresa_id, indicador_key, periodo_ano, year, period_key, tipo, analisis_positivo, analisis_negativo, recomendacion, metodología, generado_por, created_at)
VALUES 
(3099, 'propiedad_autonomia_1Q', 2025, 2025, '1Q', 'success', 'Inicias el 2025 con una autonomía financiera del 90%, lo que constituye un récord histórico de soberanía para MAS CONSULTA. Eres el dueño absoluto de tu destino comercial, operando con una libertad que te permite elegir a tus clientes y proyectos basados en valor estratégico y no por necesidad de caja inmediata.', 'Tener tanta autonomía puede generarte un sesgo de confirmación donde dejes de escuchar advertencias externas. Al no tener socios o acreedores que cuestionen tus movidas, podrías caer en gastos de vanidad corporativa que no sumen a la rentabilidad operativa real del negocio en este arranque de año tan exitoso.', 'Crea un comité de auditoría externa que evalúe tus decisiones de inversión más pesadas de inmediato. Necesitas ojos críticos que desafíen tu autonomía para que esta se convierta en una ventaja competitiva real y no en una zona de confort que te haga perder el hambre de eficiencia que te caracteriza hoy.', 'Bloque C - Trimestral 1Q 2025', 'antigravity', NOW()),
(3099, 'propiedad_autonomia_2Q', 2025, 2025, '2Q', 'success', 'Llegamos a la mitad de 2025 manteniendo niveles de propiedad neta superiores al 85%, lo que blinda a la consultora contra cualquier intento de hostilidad comercial externa. Tu autonomía es tu mayor activo reputacional; el mercado te percibe como un jugador de primer nivel con una solvencia técnica que muy pocos pueden igualar.', 'El riesgo es la "parálisis por exceso de opciones". Al tener tanta autonomía y recursos, podrías estar dispersando tu energía en demasiados frentes nuevos sin consolidar el core del negocio. La libertad total exige una disciplina de enfoque estratégica mucho mayor para no diluir el impacto de tu talento consultor neta.', 'Define los tres pilares críticos de crecimiento para el cierre de año y prohíbe cualquier gasto que no esté alineado con ellos. Usa tu autonomía para decir "no" a lo mediocre y "sí" solo a lo extraordinario. Tu meta es que tu propiedad neta financie un crecimiento láser y no un desorden corporativo expansivo hoy.', 'Bloque C - Trimestral 2Q 2025', 'antigravity', NOW()),
(3099, 'propiedad_autonomia_3Q', 2025, 2025, '3Q', 'success', 'En este tercer periodo de 2025, tu autonomía financiera te permite navegar con total tranquilidad en medio de un mercado altamente volátil. Has demostrado ser un gestor que prioriza la salud del balance sobre la escala vacía, logrando una empresa que es propiedad genuina de sus fundadores en un 88% real hoy.', 'La alerta aquí es la falta de incentivos de capital para el talento clave (Partners). Al ser tan dueño de la empresa, podrías estar limitando la llegada de socios industriales que exijan participación para entregar su conocimiento. Debes equilibrar tu deseo de autonomía con la necesidad de atraer mentes brillantes hoy.', 'Evalúa la creación de un sistema de "Phantom Shares" o bonos de rentabilidad ligados al patrimonio para tus gerentes de cuenta sénior. Permíteles sentir que son dueños de los resultados sin diluir tu autonomía jurídica. Esto asegurará la lealtad del talento sin comprometer la soberanía del balance de MAS CONSULTA neta.', 'Bloque C - Trimestral 3Q 2025', 'antigravity', NOW()),
(3099, 'propiedad_autonomia_4Q', 2025, 2025, '4Q', 'success', 'Cierre anual con una autonomía financiera del 92%, coronando un proceso de saneamiento y fortalecimiento patrimonial magistral. Has terminado el trienio como el soberano absoluto de una firma de consultoría que vale hoy tres veces más que en el 2023, y que es 100% tuya ante cualquier estándar financiero global moderno.', 'Para el próximo trienio, el reto es saber cuándo compartir esta autonomía para escalar a nivel continental. Ser el dueño del 92% de una empresa local es menos valioso que ser el dueño del 60% de una multinacional líder. No permitas que el orgullo de la propiedad frene el potencial de tu impacto en el mercado global.', 'Inicia el 2026 diseñando una estrategia de apertura de capital o alianzas de alto nivel. Tienes la solvencia para negociar participaciones desde una posición de fuerza extrema; úsala para atraer socios globales que te den la escala que hoy tu balance ya puede soportar sin riesgo alguno de insolvencia hoy.', 'Bloque C - Trimestral 4Q 2025', 'antigravity', NOW())
INSERT INTO insights (empresa_id, indicador_key, periodo_ano, year, period_key, tipo, analisis_positivo, analisis_negativo, recomendacion, metodología, generado_por, created_at)
VALUES 
(3099, 'deuda_patrimonio_1Q', 2025, 2025, '1Q', 'success', 'Inicias el 2025 con una relación deuda-patrimonio de 0.10x, lo que representa un estado de "deuda cero" operativa virtual. Tu patrimonio es diez veces superior a tus compromisos totales, lo que te otorga un perfil de riesgo prácticamente nulo y una capacidad de negociación ante proveedores y bancos que es invencible hoy.', 'El riesgo latente es la ineficiencia económica de no usar apalancamiento productivo. Al operar solo con dinero propio, estás pagando un "costo de oportunidad" muy alto, ya que podrías estar rindiendo mucho más si usaras capital de terceros para financiar tu expansión mientras mantienes tu riqueza invertida en activos neta.', 'Atrévete a tomar una deuda estratégica de bajo costo para financiar tu nueva unidad de negocios digital este semestre. Tienes la espalda patrimonial para hacerlo sin riesgo alguno; usa la deuda como un atajo para el crecimiento y no como un salvavidas de emergencia, que es como la usabas en épocas pasadas hoy.', 'Bloque C - Trimestral 1Q 2025', 'antigravity', NOW()),
(3099, 'deuda_patrimonio_2Q', 2025, 2025, '2Q', 'success', 'Llegamos a mitad de año con una relación deuda-patrimonio que es el estándar de oro de la industria consultora. Has logrado que tu riqueza neta crezca exponencialmente gracias a utilidades récord, mientras tus deudas se mantienen en niveles marginales, dándote una solidez institucional que proyecta confianza total hoy.', 'La alerta aquí es el potencial descuido de la gestión de tesorería operativa. Al tener tanto patrimonio, podrías estar permitiendo que tus cuentas por cobrar se dilaten, confiando en que tu "propio banco" patrimonial cubrirá los baches. No permitas que la solvencia te vuelva perezoso en el recaudo comercial de MAS CONSULTA.', 'Implementa un sistema de recaudo agresivo con incentivos por pronto pago de inmediato. Tu patrimonio debe ser para invertir y crecer, no para financiar gratis la operación de tus clientes. Asegura que cada peso que debas tenga un respaldo de caja inmediata y que tus deudas sigan siendo insignificantes hoy.', 'Bloque C - Trimestral 2Q 2025', 'antigravity', NOW()),
(3099, 'deuda_patrimonio_3Q', 2025, 2025, '3Q', 'success', 'En el tercer trimestre, tu relación de deuda sobre patrimonio sigue siendo magistralmente baja (0.12x). Has construido una estructura de fondeo donde los dueños son los únicos proveedores reales de capital estratégico, eliminando cualquier vulnerabilidad ante cambios en las tasas de interés o crisis de crédito nacional.', 'No obstante, vigila que esta baja deuda no sea síntoma de una falta de ambición corporativa. El mercado de hoy exige movimientos rápidos que a veces requieren deudas puentes masivas para capturar licitaciones de gran volumen. Si eres demasiado cauteloso con la deuda, podrías estarle regalando el mercado a novatos más audaces hoy.', 'Crea un cupo de deuda pre-aprobado para adquisiciones estratégicas este mes. Debes tener el gatillo listo para disparar ante una oportunidad de compra de infraestructura o talento; usa tu ratio de 0.12x como la mejor carta de presentación para que los bancos te ofrezcan cheques en blanco para tu crecimiento corporativo neta.', 'Bloque C - Trimestral 3Q 2025', 'antigravity', NOW()),
(3099, 'deuda_patrimonio_4Q', 2025, 2025, '4Q', 'success', 'Cierras el trienio 2023-2025 con una relación deuda-patrimonio de 0.10x, coronando una gestión de solvencia histórica y vencedora. Has transformado a MAS CONSULTA en una fortaleza financiera inexpugnable, donde hoy por cada peso que debes, tienes diez pesos de patrimonio neto propio respaldando la operación consolidada.', 'Para el 2026, el desafío es pasar de la "solvencia defensiva" a la "solvencia expansiva". Ya demostraste que puedes vivir sin deuda; ahora debes demostrar que puedes usarla para dominar el continente sin perder tu esencia de control patrimonial. No permitas que el miedo a deber te impida ser el más grande de la región hoy.', 'Diseña la estructura de capital para el 2026 con un objetivo de apalancamiento del 0.4x destinado exclusivamente a la internacionalización. Tienes la base patrimonial más sólida de tu historia; úsala ahora como el motor de una expansión que no conozca fronteras, manteniendo siempre tu libertad de dueño soberana neta.', 'Bloque C - Trimestral 4Q 2025', 'antigravity', NOW())
